mapper.select:
SELECT ID, WORD_STUDY_CREATE_AT, WORD_STUDY_UPDATE_AT, WORD_STUDY_IS_COMPLETED, EDU_WORD_MAP_ID, USER_ID
FROM TBL_WORD_STUDY
WHERE USER_ID = #{userId}
  AND EDU_WORD_MAP_ID = #{eduWordMapId}

SELECT COUNT(*)
FROM TBL_EDU_WORD_MAP
WHERE EDU_ID = #{eduId}

mapper.update:
UPDATE TBL_WORD_STUDY
SET WORD_STUDY_IS_COMPLETED = #{wordStudyIsCompleted}, WORD_STUDY_UPDATE_AT = CURRENT_TIMESTAMP
WHERE USER_ID = #{userId}
  AND EDU_WORD_MAP_ID = #{eduWordMapId}
